// Canonical ledger encoding: `${id}|${amountCents}|${cc}` where
// cc = String((id + amountCents) % 97).padStart(2, "0").
function checksum(id, amountCents) {
  return String((id + amountCents) % 97).padStart(2, "0");
}
function encode(record) {
  const { id, amountCents } = record;
  return `${id}|${amountCents}|${checksum(id, amountCents)}`;
}
module.exports = { encode, checksum };
